{{-- Metric glyph for the tinted chip. x-icon needs a static name in Blade, so the
     per-metric icon is picked here by an x-if on `m.icon`. Used by the desktop
     rail + the mobile metric selector. --}}
<template x-if="m.icon === 'heart'"><svg class="h-4 w-4 shrink-0 text-white" fill="none" viewBox="0 0 24 24" stroke-width="1.7" stroke="currentColor" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M21 8.25c0-2.485-2.099-4.5-4.688-4.5-1.935 0-3.597 1.126-4.312 2.733-.715-1.607-2.377-2.733-4.313-2.733C5.1 3.75 3 5.765 3 8.25c0 7.22 9 12 9 12s9-4.78 9-12z" /></svg></template>
<template x-if="m.icon === 'beaker'"><svg class="h-4 w-4 shrink-0 text-white" fill="none" viewBox="0 0 24 24" stroke-width="1.7" stroke="currentColor" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M14.25 2.25v7.5L18 15.75H6L9.75 9.75V2.25M10.5 2.25h3M3.75 21h16.5" /></svg></template>
<template x-if="m.icon === 'thermometer'"><svg class="h-4 w-4 shrink-0 text-white" fill="none" viewBox="0 0 24 24" stroke-width="1.7" stroke="currentColor" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M12 9v6m0 6a3 3 0 100-6 3 3 0 000 6zm0-9V3m0 6a3 3 0 013 3m-6 0a3 3 0 013-3" /></svg></template>
<template x-if="m.icon === 'scale'"><svg class="h-4 w-4 shrink-0 text-white" fill="none" viewBox="0 0 24 24" stroke-width="1.7" stroke="currentColor" aria-hidden="true"><path stroke-linecap="round" stroke-linejoin="round" d="M12 3v1.5M12 3c-1.2 0-2.4.6-3 1.5L3 16.5h18L15 4.5C14.4 3.6 13.2 3 12 3zm0 1.5L6 16.5m6-12l6 12M3 16.5h18v1.5a2.25 2.25 0 01-2.25 2.25H5.25A2.25 2.25 0 013 18v-1.5z" /></svg></template>
